query:
ALTER TABLE users ADD COLUMN IF NOT EXISTS timezone varchar(80) NOT NULL DEFAULT 'UTC';
ALTER TABLE users ADD COLUMN IF NOT EXISTS preferredHour int NOT NULL DEFAULT 9;
ALTER TABLE users ADD COLUMN IF NOT EXISTS workoutReminderEnabled boolean NOT NULL DEFAULT false;
ALTER TABLE users ADD COLUMN IF NOT EXISTS mealReminderEnabled boolean NOT NULL DEFAULT false;
ALTER TABLE users ADD COLUMN IF NOT EXISTS calorieTarget int NOT NULL DEFAULT 2200;
ALTER TABLE users ADD COLUMN IF NOT EXISTS proteinTarget int NOT NULL DEFAULT 180;
ALTER TABLE users ADD COLUMN IF NOT EXISTS carbTarget int NOT NULL DEFAULT 220;
ALTER TABLE users ADD COLUMN IF NOT EXISTS fatTarget int NOT NULL DEFAULT 70;
CREATE TABLE IF NOT EXISTS workoutLogs (
  id int AUTO_INCREMENT PRIMARY KEY,
  userId int NOT NULL,
  title varchar(160) NOT NULL,
  workoutDate timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  durationMinutes int NOT NULL DEFAULT 0,
  totalVolume int NOT NULL DEFAULT 0,
  notes text NULL,
  createdAt timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE IF NOT EXISTS workoutExercises (
  id int AUTO_INCREMENT PRIMARY KEY,
  workoutId int NOT NULL,
  name varchar(160) NOT NULL,
  sets int NOT NULL DEFAULT 0,
  reps int NOT NULL DEFAULT 0,
  weight int NOT NULL DEFAULT 0,
  durationMinutes int NOT NULL DEFAULT 0
);
CREATE TABLE IF NOT EXISTS mealLogs (
  id int AUTO_INCREMENT PRIMARY KEY,
  userId int NOT NULL,
  name varchar(180) NOT NULL,
  mealType varchar(60) NOT NULL DEFAULT 'meal',
  mealDate timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  calories int NOT NULL DEFAULT 0,
  protein int NOT NULL DEFAULT 0,
  carbs int NOT NULL DEFAULT 0,
  fat int NOT NULL DEFAULT 0,
  source varchar(80) NOT NULL DEFAULT 'manual',
  notes text NULL,
  createdAt timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE IF NOT EXISTS chatMessages (
  id int AUTO_INCREMENT PRIMARY KEY,
  userId int NOT NULL,
  role enum('user','assistant') NOT NULL,
  content text NOT NULL,
  createdAt timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP
);

